import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { 
  FiPlus, FiTrendingUp, FiBell, FiShoppingBag, FiTrash2, 
  FiDollarSign, FiClock, FiZap, FiStar, FiTrendingDown,
  FiBarChart2, FiTarget, FiAward, FiActivity
} from 'react-icons/fi';

const API_URL = 'http://localhost:5000/api';

function Dashboard() {
  const [products, setProducts] = useState([]);
  const [stats, setStats] = useState({
    total_products: 0,
    buy_now: 0,
    wait: 0,
    buy_soon: 0
  });
  const [showAddModal, setShowAddModal] = useState(false);
  const [newProductUrl, setNewProductUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [deletingId, setDeletingId] = useState(null);
  const [hoveredCard, setHoveredCard] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProducts();
    fetchStats();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await axios.get(`${API_URL}/products`, {
        withCredentials: true
      });
      setProducts(response.data || []);
    } catch (error) {
      console.error('Error fetching products:', error);
      toast.error('Failed to load products');
      setProducts([]);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_URL}/dashboard/stats`, {
        withCredentials: true
      });
      setStats(response.data || {
        total_products: 0,
        buy_now: 0,
        wait: 0,
        buy_soon: 0
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const addProduct = async () => {
    if (!newProductUrl.trim()) {
      toast.error('Please enter a product URL');
      return;
    }

    setLoading(true);
    try {
      await axios.post(`${API_URL}/products`, 
        { url: newProductUrl },
        { withCredentials: true }
      );
      toast.success('Product added successfully!');
      setShowAddModal(false);
      setNewProductUrl('');
      await fetchProducts();
      await fetchStats();
    } catch (error) {
      console.error('Error adding product:', error);
      toast.error(error.response?.data?.error || 'Failed to add product');
    } finally {
      setLoading(false);
    }
  };

  const deleteProduct = async (productId, event) => {
    event.stopPropagation();
    
    if (!window.confirm('Are you sure you want to remove this product?')) {
      return;
    }
    
    setDeletingId(productId);
    try {
      await axios.delete(`${API_URL}/products/${productId}`, {
        withCredentials: true
      });
      toast.success('Product removed successfully');
      await fetchProducts();
      await fetchStats();
    } catch (error) {
      console.error('Error deleting product:', error);
      toast.error('Failed to remove product');
    } finally {
      setDeletingId(null);
    }
  };

  const getDecisionStyle = (decision) => {
    switch(decision) {
      case 'BUY_NOW':
        return {
          gradient: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          icon: <FiZap />,
          text: 'BUY NOW',
          color: '#667eea'
        };
      case 'BUY_SOON':
        return {
          gradient: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          icon: <FiClock />,
          text: 'BUY SOON',
          color: '#f5576c'
        };
      default:
        return {
          gradient: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
          icon: <FiTrendingDown />,
          text: 'WAIT',
          color: '#4facfe'
        };
    }
  };

  const getConfidenceColor = (confidence) => {
    if (confidence >= 70) return '#48bb78';
    if (confidence >= 50) return '#ecc94b';
    return '#f56565';
  };

  return (
    <div className="dashboard-container">
      {/* Animated Background */}
      <div className="animated-bg">
        <div className="gradient-sphere sphere-1"></div>
        <div className="gradient-sphere sphere-2"></div>
        <div className="gradient-sphere sphere-3"></div>
      </div>

      {/* Welcome Section */}
      <div className="welcome-section">
        <div className="welcome-content">
          <h1 className="welcome-title">
            Smart Price Decision Dashboard
            <span className="title-badge">AI Powered</span>
          </h1>
          <p className="welcome-subtitle">
            Track prices, get intelligent recommendations, and never miss a great deal
          </p>
        </div>
        <button className="add-product-btn-glass" onClick={() => setShowAddModal(true)}>
          <FiPlus size={20} />
          <span>Track New Product</span>
        </button>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card-glass">
          <div className="stat-icon total-icon">
            <FiShoppingBag />
          </div>
          <div className="stat-info">
            <h3>{stats.total_products}</h3>
            <p>Total Products</p>
          </div>
          <div className="stat-trend">
            <FiBarChart2 />
          </div>
        </div>

        <div className="stat-card-glass buy-now-stat">
          <div className="stat-icon">
            <FiZap />
          </div>
          <div className="stat-info">
            <h3>{stats.buy_now}</h3>
            <p>Buy Now</p>
          </div>
          <div className="stat-badge">Hot Deal</div>
        </div>

        <div className="stat-card-glass buy-soon-stat">
          <div className="stat-icon">
            <FiClock />
          </div>
          <div className="stat-info">
            <h3>{stats.buy_soon}</h3>
            <p>Buy Soon</p>
          </div>
          <div className="stat-badge">Act Fast</div>
        </div>

        <div className="stat-card-glass wait-stat">
          <div className="stat-icon">
            <FiTrendingDown />
          </div>
          <div className="stat-info">
            <h3>{stats.wait}</h3>
            <p>Wait</p>
          </div>
          <div className="stat-badge">Patience</div>
        </div>
      </div>

      {/* Products Section Header */}
      <div className="products-header">
        <div className="products-title-section">
          <FiTarget className="section-icon" />
          <h2>Your Tracked Products</h2>
          <span className="product-count">{products.length} items</span>
        </div>
        <div className="products-filters">
          <button className="filter-btn active">All</button>
          <button className="filter-btn">Buy Now</button>
          <button className="filter-btn">Buy Soon</button>
          <button className="filter-btn">Wait</button>
        </div>
      </div>

      {/* Products Grid */}
      {products.length === 0 ? (
        <div className="empty-state-glass">
          <div className="empty-animation">
            <FiShoppingBag size={80} />
          </div>
          <h3>No products tracked yet</h3>
          <p>Start tracking products to get AI-powered purchase recommendations</p>
          <button className="cta-button" onClick={() => setShowAddModal(true)}>
            <FiPlus /> Add Your First Product
          </button>
        </div>
      ) : (
        <div className="products-grid">
          {products.map((product, index) => {
            const decisionStyle = getDecisionStyle(product.decision);
            const confidenceColor = getConfidenceColor(product.confidence);
            const savings = product.original_price && product.original_price > product.current_price 
              ? (product.original_price - product.current_price).toFixed(2) 
              : null;
            
            return (
              <div 
                key={product.id} 
                className={`product-card-glass ${hoveredCard === product.id ? 'hovered' : ''}`}
                onClick={() => navigate(`/product/${product.id}`)}
                onMouseEnter={() => setHoveredCard(product.id)}
                onMouseLeave={() => setHoveredCard(null)}
                style={{ animationDelay: `${index * 0.1}s` }}
              >
                <div className="card-badge" style={{ background: decisionStyle.gradient }}>
                  {decisionStyle.icon}
                  <span>{decisionStyle.text}</span>
                </div>
                
                <button 
                  className="card-delete"
                  onClick={(e) => deleteProduct(product.id, e)}
                  disabled={deletingId === product.id}
                >
                  <FiTrash2 />
                </button>

                <div className="card-content">
                  <h3 className="product-name">{product.name || 'Product'}</h3>
                  
                  <div className="price-section">
                    <div className="current-price">
                      <span className="currency">$</span>
                      <span className="amount">{(product.current_price || 0).toFixed(2)}</span>
                    </div>
                    {product.original_price && product.original_price > product.current_price && (
                      <div className="original-price">
                        ${product.original_price.toFixed(2)}
                      </div>
                    )}
                  </div>

                  {savings && (
                    <div className="savings-badge">
                      <FiStar size={12} />
                      <span>Save ${savings}</span>
                    </div>
                  )}

                  <div className="confidence-section">
                    <div className="confidence-bar">
                      <div 
                        className="confidence-fill"
                        style={{ 
                          width: `${product.confidence || 0}%`,
                          background: confidenceColor
                        }}
                      />
                    </div>
                    <div className="confidence-text">
                      <FiActivity size={12} />
                      <span>{product.confidence || 0}% confidence</span>
                    </div>
                  </div>

                  <div className="card-footer">
                    <div className="product-id">ID: {product.id}</div>
                    <div className="view-details">
                      View Details <span>→</span>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Add Product Modal */}
      {showAddModal && (
        <div className="modal-overlay" onClick={() => setShowAddModal(false)}>
          <div className="modal-glass" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Add New Product</h3>
              <button className="modal-close" onClick={() => setShowAddModal(false)}>×</button>
            </div>
            <div className="modal-body">
              <p>Enter any product URL from Amazon, Flipkart, or any e-commerce store</p>
              <div className="url-input-wrapper">
                <FiShoppingBag className="input-icon" />
                <input
                  type="text"
                  placeholder="https://www.amazon.com/product/dp/..."
                  value={newProductUrl}
                  onChange={(e) => setNewProductUrl(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addProduct()}
                  autoFocus
                />
              </div>
              <div className="example-urls">
                <span>Try:</span>
                <button className="example-btn" onClick={() => setNewProductUrl('https://www.amazon.com/Sony-Headphones/dp/B0B4B8R8R9')}>
                  Sony Headphones
                </button>
                <button className="example-btn" onClick={() => setNewProductUrl('https://www.amazon.com/Apple-iPhone/dp/B0CM5J7L7T')}>
                  iPhone 15
                </button>
              </div>
            </div>
            <div className="modal-footer">
              <button className="modal-cancel" onClick={() => setShowAddModal(false)}>
                Cancel
              </button>
              <button className="modal-submit" onClick={addProduct} disabled={loading}>
                {loading ? 'Adding...' : 'Add Product'}
              </button>
            </div>
          </div>
        </div>
      )}

      <style jsx>{`
        .dashboard-container {
          min-height: 100vh;
          padding: 20px;
          position: relative;
          overflow-x: hidden;
        }

        /* Animated Background */
        .animated-bg {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          z-index: 0;
          overflow: hidden;
        }

        .gradient-sphere {
          position: absolute;
          border-radius: 50%;
          filter: blur(80px);
          opacity: 0.3;
          animation: float 20s infinite ease-in-out;
        }

        .sphere-1 {
          width: 500px;
          height: 500px;
          background: linear-gradient(135deg, #667eea, #764ba2);
          top: -200px;
          left: -200px;
          animation-delay: 0s;
        }

        .sphere-2 {
          width: 600px;
          height: 600px;
          background: linear-gradient(135deg, #f093fb, #f5576c);
          bottom: -250px;
          right: -200px;
          animation-delay: 5s;
        }

        .sphere-3 {
          width: 400px;
          height: 400px;
          background: linear-gradient(135deg, #4facfe, #00f2fe);
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          animation-delay: 10s;
        }

        @keyframes float {
          0%, 100% { transform: translate(0, 0) rotate(0deg); }
          33% { transform: translate(30px, -30px) rotate(120deg); }
          66% { transform: translate(-20px, 20px) rotate(240deg); }
        }

        /* Welcome Section */
        .welcome-section {
          position: relative;
          z-index: 1;
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 40px;
          flex-wrap: wrap;
          gap: 20px;
        }

        .welcome-title {
          font-size: 2rem;
          font-weight: 700;
          background: linear-gradient(135deg, #fff 0%, #a0aec0 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          margin-bottom: 10px;
          display: flex;
          align-items: center;
          gap: 15px;
          flex-wrap: wrap;
        }

        .title-badge {
          background: linear-gradient(135deg, #667eea, #764ba2);
          padding: 4px 12px;
          border-radius: 20px;
          font-size: 0.8rem;
          color: white;
          -webkit-text-fill-color: white;
        }

        .welcome-subtitle {
          color: var(--text-secondary);
          font-size: 0.95rem;
        }

        .add-product-btn-glass {
          background: rgba(255, 255, 255, 0.1);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.2);
          padding: 12px 24px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          gap: 8px;
          font-weight: 600;
          transition: all 0.3s ease;
        }

        .add-product-btn-glass:hover {
          background: rgba(255, 255, 255, 0.2);
          transform: translateY(-2px);
        }

        /* Stats Grid */
        .stats-grid {
          position: relative;
          z-index: 1;
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
          gap: 20px;
          margin-bottom: 40px;
        }

        .stat-card-glass {
          background: rgba(255, 255, 255, 0.05);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.1);
          border-radius: 20px;
          padding: 20px;
          display: flex;
          align-items: center;
          justify-content: space-between;
          transition: all 0.3s ease;
          position: relative;
          overflow: hidden;
        }

        .stat-card-glass:hover {
          transform: translateY(-4px);
          border-color: rgba(255, 255, 255, 0.3);
        }

        .stat-icon {
          width: 50px;
          height: 50px;
          border-radius: 15px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 24px;
          background: rgba(255, 255, 255, 0.1);
        }

        .total-icon {
          background: linear-gradient(135deg, #667eea, #764ba2);
        }

        .stat-info h3 {
          font-size: 2rem;
          font-weight: 700;
          margin: 0;
        }

        .stat-info p {
          margin: 5px 0 0;
          color: var(--text-secondary);
          font-size: 0.85rem;
        }

        .stat-badge {
          background: rgba(255, 255, 255, 0.15);
          padding: 4px 10px;
          border-radius: 12px;
          font-size: 0.7rem;
          font-weight: 600;
        }

        /* Products Header */
        .products-header {
          position: relative;
          z-index: 1;
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 30px;
          flex-wrap: wrap;
          gap: 15px;
        }

        .products-title-section {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .section-icon {
          font-size: 24px;
          color: #667eea;
        }

        .products-title-section h2 {
          font-size: 1.5rem;
          font-weight: 600;
        }

        .product-count {
          background: rgba(102, 126, 234, 0.2);
          padding: 4px 10px;
          border-radius: 20px;
          font-size: 0.85rem;
          color: #667eea;
        }

        .products-filters {
          display: flex;
          gap: 10px;
        }

        .filter-btn {
          background: rgba(255, 255, 255, 0.05);
          border: 1px solid rgba(255, 255, 255, 0.1);
          padding: 8px 16px;
          border-radius: 10px;
          font-size: 0.85rem;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .filter-btn:hover, .filter-btn.active {
          background: rgba(102, 126, 234, 0.3);
          border-color: #667eea;
        }

        /* Products Grid */
        .products-grid {
          position: relative;
          z-index: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
          gap: 25px;
        }

        .product-card-glass {
          background: rgba(255, 255, 255, 0.05);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.1);
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
          cursor: pointer;
          position: relative;
          animation: fadeInUp 0.6s ease backwards;
        }

        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .product-card-glass:hover {
          transform: translateY(-8px) scale(1.02);
          border-color: rgba(102, 126, 234, 0.5);
          box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
        }

        .card-badge {
          position: absolute;
          top: 15px;
          left: 15px;
          padding: 6px 14px;
          border-radius: 20px;
          display: flex;
          align-items: center;
          gap: 6px;
          font-size: 0.75rem;
          font-weight: 700;
          z-index: 2;
        }

        .card-delete {
          position: absolute;
          top: 15px;
          right: 15px;
          background: rgba(0, 0, 0, 0.5);
          border: none;
          width: 30px;
          height: 30px;
          border-radius: 8px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          opacity: 0;
          transition: all 0.3s ease;
          z-index: 2;
        }

        .product-card-glass:hover .card-delete {
          opacity: 1;
        }

        .card-delete:hover {
          background: #f56565;
          transform: scale(1.1);
        }

        .card-content {
          padding: 25px;
        }

        .product-name {
          font-size: 1rem;
          font-weight: 600;
          margin-bottom: 15px;
          color: var(--text-primary);
          line-height: 1.4;
          min-height: 48px;
        }

        .price-section {
          display: flex;
          align-items: baseline;
          gap: 10px;
          margin-bottom: 12px;
        }

        .current-price {
          display: flex;
          align-items: baseline;
        }

        .currency {
          font-size: 1.2rem;
          font-weight: 600;
          color: #48bb78;
        }

        .amount {
          font-size: 2rem;
          font-weight: 700;
          color: #48bb78;
        }

        .original-price {
          text-decoration: line-through;
          color: var(--text-secondary);
          font-size: 0.9rem;
        }

        .savings-badge {
          display: inline-flex;
          align-items: center;
          gap: 5px;
          background: rgba(72, 187, 120, 0.2);
          padding: 4px 10px;
          border-radius: 12px;
          font-size: 0.75rem;
          color: #48bb78;
          margin-bottom: 15px;
        }

        .confidence-section {
          margin: 15px 0;
        }

        .confidence-bar {
          height: 6px;
          background: rgba(255, 255, 255, 0.1);
          border-radius: 3px;
          overflow: hidden;
          margin-bottom: 8px;
        }

        .confidence-fill {
          height: 100%;
          border-radius: 3px;
          transition: width 0.5s ease;
        }

        .confidence-text {
          display: flex;
          align-items: center;
          gap: 5px;
          font-size: 0.75rem;
          color: var(--text-secondary);
        }

        .card-footer {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-top: 15px;
          padding-top: 15px;
          border-top: 1px solid rgba(255, 255, 255, 0.1);
          font-size: 0.75rem;
        }

        .product-id {
          color: var(--text-secondary);
        }

        .view-details {
          color: #667eea;
          font-weight: 600;
          transition: all 0.3s ease;
        }

        .product-card-glass:hover .view-details {
          transform: translateX(5px);
        }

        /* Empty State */
        .empty-state-glass {
          position: relative;
          z-index: 1;
          text-align: center;
          padding: 80px 20px;
          background: rgba(255, 255, 255, 0.05);
          backdrop-filter: blur(10px);
          border-radius: 30px;
          border: 1px solid rgba(255, 255, 255, 0.1);
        }

        .empty-animation {
          margin-bottom: 20px;
          animation: bounce 2s infinite;
        }

        @keyframes bounce {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }

        .cta-button {
          margin-top: 20px;
          background: linear-gradient(135deg, #667eea, #764ba2);
          padding: 12px 24px;
          border-radius: 12px;
          display: inline-flex;
          align-items: center;
          gap: 8px;
        }

        /* Modal */
        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.8);
          backdrop-filter: blur(8px);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 1000;
          animation: fadeIn 0.3s ease;
        }

        .modal-glass {
          background: rgba(30, 30, 40, 0.95);
          backdrop-filter: blur(20px);
          border-radius: 24px;
          width: 90%;
          max-width: 500px;
          overflow: hidden;
          animation: slideUp 0.3s ease;
        }

        @keyframes slideUp {
          from {
            transform: translateY(50px);
            opacity: 0;
          }
          to {
            transform: translateY(0);
            opacity: 1;
          }
        }

        .modal-header {
          padding: 20px 25px;
          border-bottom: 1px solid rgba(255, 255, 255, 0.1);
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .modal-header h3 {
          font-size: 1.3rem;
        }

        .modal-close {
          background: none;
          border: none;
          font-size: 28px;
          cursor: pointer;
          color: var(--text-secondary);
        }

        .modal-body {
          padding: 25px;
        }

        .url-input-wrapper {
          position: relative;
          margin: 20px 0;
        }

        .input-icon {
          position: absolute;
          left: 12px;
          top: 50%;
          transform: translateY(-50%);
          color: var(--text-secondary);
        }

        .url-input-wrapper input {
          width: 100%;
          padding: 12px 12px 12px 40px;
          background: rgba(255, 255, 255, 0.1);
          border: 1px solid rgba(255, 255, 255, 0.2);
          border-radius: 12px;
          color: var(--text-primary);
          font-size: 0.9rem;
        }

        .example-urls {
          display: flex;
          align-items: center;
          gap: 8px;
          flex-wrap: wrap;
          margin-top: 15px;
          font-size: 0.8rem;
          color: var(--text-secondary);
        }

        .example-btn {
          background: rgba(102, 126, 234, 0.2);
          padding: 4px 10px;
          border-radius: 8px;
          font-size: 0.75rem;
        }

        .modal-footer {
          padding: 20px 25px;
          border-top: 1px solid rgba(255, 255, 255, 0.1);
          display: flex;
          justify-content: flex-end;
          gap: 12px;
        }

        .modal-cancel {
          background: rgba(255, 255, 255, 0.1);
          padding: 10px 20px;
        }

        .modal-submit {
          background: linear-gradient(135deg, #667eea, #764ba2);
          padding: 10px 24px;
        }

        @media (max-width: 768px) {
          .products-grid {
            grid-template-columns: 1fr;
          }
          
          .welcome-title {
            font-size: 1.5rem;
          }
          
          .stats-grid {
            grid-template-columns: repeat(2, 1fr);
          }
        }
      `}</style>
    </div>
  );
}

export default Dashboard;
